// app/360/[sceneId]/page.tsx
import { notFound } from 'next/navigation';
import scenesData from '@/components/360/data/scenes.json';
import VirtualTourClient from '@/components/360/VirtualTourClient';
import type { Scene } from '@/components/360/types';

// EXPLICIT RETURN TYPE - This is crucial for Next.js 15+
export async function generateStaticParams(): Promise<{ sceneId: string }[]> {
  return scenesData.scenes.map((scene) => ({
    sceneId: scene.id,
  }));
}

// Force static generation (optional but recommended for clarity)
export const dynamic = 'force-static';
export const dynamicParams = false;

interface PageProps {
  params: Promise<{
    sceneId: string;
  }>;
}

export default async function ScenePage({ params }: PageProps) {
  const { sceneId } = await params;
  
  const scene = scenesData.scenes.find((s) => s.id === sceneId) as Scene | undefined;
  
  if (!scene) {
    notFound();
  }

  const allScenes = scenesData.scenes as Scene[];

  return <VirtualTourClient scene={scene} allScenes={allScenes} />;
}